func TestEnumExampleStyle(t *testing.T) {
	t.Run("NewFromString_minimal", func(t *testing.T) {
		t.Parallel()
		val, err := NewExampleStyleFromString("minimal")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, ExampleStyle("minimal"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_comprehensive", func(t *testing.T) {
		t.Parallel()
		val, err := NewExampleStyleFromString("comprehensive")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, ExampleStyle("comprehensive"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewExampleStyleFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewExampleStyleFromString("minimal")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

func TestExtraPropertiesCargoPublishInfo(t *testing.T) {
	t.Run("GetExtraProperties", func(t *testing.T) {
		t.Parallel()
		obj := &CargoPublishInfo{}
		// Should not panic when calling GetExtraProperties()
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("GetExtraProperties() panicked: %v", r)
			}
		}()
		extraProps := obj.GetExtraProperties()
		// Result can be nil or an empty/non-empty map
		_ = extraProps
	})

	t.Run("GetExtraProperties_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *CargoPublishInfo
		extraProps := obj.GetExtraProperties()
		assert.Nil(t, extraProps, "nil receiver should return nil without panicking")
	})
}

